func solve(n int64) bool {
    if n == 0 {
        return false
    }
    original := n
    var sum int64 = 0
    var product int64 = 1
    for n > 0 {
        digit := n % 10
        sum += digit
        product *= digit
        n /= 10
    }
    total := sum + product
    return total != 0 && original % total == 0
}
